const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [];
if (!alerts.length) return [];

const alert = alerts[0];
const runId = alert.labels?.run_id;
const key = `${alert.labels?.alertname}:${alert.labels?.namespace}:${alert.status}`;
const now = Date.now();
const store = $getWorkflowStaticData('global');
store.seen = store.seen || {};

// run_id bypasses dedup entirely (for testing)
if (runId) {
  console.log(`DEDUP BYPASS | run_id=${runId} | key=${key}`);
  store.seen[key] = now;
  return [{ json: { alert, body, timestamp: new Date().toISOString() } }];
}

if (store.seen[key] && now - store.seen[key] < 600000) {
  const ageMin = Math.round((now - store.seen[key]) / 60000);
  console.log(`DEDUP DROP | ${key} | seen ${ageMin}min ago (window=10min)`);
  // Return output so n8n shows why it stopped
  return [{ json: { deduped: true, reason: `Already seen ${ageMin}min ago`, key, nextAllowedIn: `${10 - ageMin}min` } }];
}

store.seen[key] = now;
return [{ json: { alert, body, timestamp: new Date().toISOString() } }];

const data = $input.first().json;
// Get alert from direct field OR from body.alerts[0] as fallback
const alert = (data.alert && data.alert.labels) ? data.alert : (data.body?.alerts?.[0] || {});
const labels = alert.labels || {};
const annotations = alert.annotations || {};

const alertname = labels.alertname || data.body?.commonLabels?.alertname || 'Unknown';
const namespace = labels.namespace || labels.exported_namespace || 'workshop';
const pod = labels.pod || labels.exported_pod || '';
const severity = labels.severity || 'warning';
const status = alert.status || data.body?.status || 'firing';
const summary = annotations.summary || data.body?.commonAnnotations?.summary || alertname;
const description = annotations.description || data.body?.commonAnnotations?.description || '';

const signalMap = {
  TargetAppCPUStress: [
    { name: 'cpu_active', query: `target_chaos_cpu_active{namespace="${namespace}"}`, label: 'CPU Stress' },
    { name: 'memory_active', query: `target_chaos_memory_active{namespace="${namespace}"}`, label: 'Memory Leak' },
    { name: 'restarts', query: `increase(kube_pod_container_status_restarts_total{namespace="${namespace}",pod=~"target-app.*"}[5m])`, label: 'Pod Restarts' }
  ],
  TargetAppMemoryLeak: [
    { name: 'memory_active', query: `target_chaos_memory_active{namespace="${namespace}"}`, label: 'Memory Leak' },
    { name: 'memory_bytes', query: `target_chaos_memory_bytes{namespace="${namespace}"}`, label: 'Memory Allocated' },
    { name: 'cpu_active', query: `target_chaos_cpu_active{namespace="${namespace}"}`, label: 'CPU Stress' }
  ],
  TargetAppMemoryCritical: [
    { name: 'memory_bytes', query: `target_chaos_memory_bytes{namespace="${namespace}"}`, label: 'Memory Allocated' },
    { name: 'memory_active', query: `target_chaos_memory_active{namespace="${namespace}"}`, label: 'Memory Leak Active' },
    { name: 'cpu_active', query: `target_chaos_cpu_active{namespace="${namespace}"}`, label: 'CPU Stress' }
  ],
  TargetAppCrashLooping: [
    { name: 'restarts', query: `increase(kube_pod_container_status_restarts_total{namespace="${namespace}",pod=~"target-app.*"}[5m])`, label: 'Pod Restarts' },
    { name: 'not_ready', query: `kube_pod_status_ready{namespace="${namespace}",condition="true",pod=~"target-app.*"}`, label: 'Pod Ready' },
    { name: 'memory_active', query: `target_chaos_memory_active{namespace="${namespace}"}`, label: 'Memory Leak' }
  ]
};

const signals = signalMap[alertname] || [
  { name: 'restarts', query: `increase(kube_pod_container_status_restarts_total{namespace="${namespace}"}[5m])`, label: 'Pod Restarts' }
];

return [{ json: { alertname, namespace, pod, severity, status, summary, description, signals, alert, body: data.body } }];

const input = $input.first().json;
const { alertname, namespace, pod, severity, status, summary, description, signals, alert, body } = input;

// Pass through without PromQL calls — AI Agent will verify signals directly
// Pre-set confidence to MEDIUM so it always escalates to AI Agent
return [{ json: {
  alertname, namespace, pod, severity, status, summary, description, alert, body,
  signals: signals.map(s => ({ ...s, value: 0, active: false })),
  activeCount: 0, totalCount: signals.length,
  confidencePct: 50, confidenceLabel: 'MEDIUM',
  durationStr: (() => {
    try {
      const startsAt = alert?.startsAt || '';
      if (startsAt && !startsAt.startsWith('0001')) {
        const secs = Math.round((Date.now() - new Date(startsAt).getTime()) / 1000);
        return secs < 60 ? `${secs}s` : `${Math.floor(secs/60)}m ${secs%60}s`;
      }
    } catch(e) {}
    return 'unknown';
  })()
} }];

// Low confidence — just log, don't escalate
const { alertname, namespace, confidenceLabel, confidencePct } = $input.first().json;
console.log(`S5 LOW CONFIDENCE | ${alertname} | ${namespace} | ${confidencePct}% — not escalating`);
return [];

const enriched = $('PromQL Enrichment + Confidence').first().json;
const agentOutput = $input.first().json.output || '';

const { alertname, namespace, pod, severity, durationStr, status } = enriched;

// Extract from AI Agent output
const aiConfMatch = agentOutput.match(/Confidence:\s*(HIGH|MEDIUM|LOW)/i);
const aiConfidence = aiConfMatch ? aiConfMatch[1].toUpperCase() : 'MEDIUM';

// Extract SRE_ACTION — single line only
const actionMatch = agentOutput.match(/SRE_ACTION:\s*(kubectl[^\n]+)/);
const sreAction = actionMatch ? actionMatch[1].trim() : null;

// Store incident in MCP if there's an action
let incidentKey = null;
if (sreAction) {
  try {
    const resp = await $httpRequest({
      method: 'POST',
      url: 'http://mcp-server:8000/incidents',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        alertname, namespace, pod,
        command: sreAction
      })
    });
    incidentKey = resp.key;
  } catch(e) {
    console.log('Incident store failed:', e.message);
  }
}

// Clean analysis
const analysis = agentOutput
  .replace(/SRE_ACTION:.+/gs, '')
  .replace(/Confidence:\s*(HIGH|MEDIUM|LOW)/gi, '')
  .trim();

const confBadge = { HIGH: '🔴 HIGH', MEDIUM: '🟡 MEDIUM', LOW: '🟢 LOW' }[aiConfidence] || aiConfidence;
const sevEmoji = severity === 'critical' ? '🚨' : '⚠️';
const statusLine = status === 'firing' ? '🔥 FIRING' : '✅ RESOLVED';

let msg = `${sevEmoji} <b>INCIDENT DETECTED</b>`;
if (incidentKey) msg += ` <code>#${incidentKey}</code>`;
msg += `\n`;
msg += `━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📍 <b>${pod || 'target-app'}</b> / <code>${namespace}</code>\n`;
msg += `🏷 <b>${alertname}</b> — ${statusLine}\n`;
msg += `⏱ Duration: <b>${durationStr}</b>\n`;
msg += `🔍 Confidence: <b>${confBadge}</b>\n\n`;

msg += `🧠 <b>AI Assessment</b>\n`;
msg += `<i>${analysis}</i>\n\n`;

if (sreAction) {
  msg += `✅ <b>Recommended Action</b>\n`;
  msg += `<code>${sreAction}</code>\n\n`;
  msg += `💬 Reply: <code>/approve &lt;totp&gt; ${incidentKey || ''}</code>\n`;
} else {
  msg += `ℹ️ No write action required — monitoring only\n`;
}

msg += `━━━━━━━━━━━━━━━━━━━━\n`;
msg += `🕐 ${new Date().toISOString().replace('T', ' ').slice(0, 19)} UTC`;

return [{ json: { message: msg, sreAction, aiConfidence, alertname, namespace, incidentKey } }];

const { alertname, namespace, confidenceLabel } = $input.first().json;
const msg = `❌ <b>S5 Error</b>\nFailed processing: ${alertname} (${namespace})\nConfidence was: ${confidenceLabel}`;
return [{ json: { message: msg } }];

const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [];
if (!alerts.length) return [];

const alert = alerts[0];
const runId = alert.labels?.run_id;
const key = `${alert.labels?.alertname}:${alert.labels?.namespace}:${alert.status}`;
const now = Date.now();
const store = $getWorkflowStaticData('global');
store.seen = store.seen || {};

// run_id bypasses dedup entirely (for testing)
if (runId) {
  console.log(`DEDUP BYPASS | run_id=${runId} | key=${key}`);
  store.seen[key] = now;
  return [{ json: { alert, body, timestamp: new Date().toISOString() } }];
}

if (store.seen[key] && now - store.seen[key] < 600000) {
  const ageMin = Math.round((now - store.seen[key]) / 60000);
  console.log(`DEDUP DROP | ${key} | seen ${ageMin}min ago (window=10min)`);
  // Return output so n8n shows why it stopped
  return [{ json: { deduped: true, reason: `Already seen ${ageMin}min ago`, key, nextAllowedIn: `${10 - ageMin}min` } }];
}

store.seen[key] = now;
return [{ json: { alert, body, timestamp: new Date().toISOString() } }];

const data = $input.first().json;
const alert = data.alert || {};
const labels = alert.labels || {};
const annotations = alert.annotations || {};

const alertname = labels.alertname || 'Unknown';
const namespace = labels.namespace || labels.exported_namespace || 'workshop';
const pod = labels.pod || labels.exported_pod || '';
const severity = labels.severity || 'warning';
const status = alert.status || 'firing';
const summary = annotations.summary || alertname;
const description = annotations.description || '';

const signalMap = {
  TargetAppCPUStress: [
    { name: 'cpu_active', query: `target_chaos_cpu_active{namespace="${namespace}"}`, label: 'CPU Stress' },
    { name: 'memory_active', query: `target_chaos_memory_active{namespace="${namespace}"}`, label: 'Memory Leak' },
    { name: 'restarts', query: `increase(kube_pod_container_status_restarts_total{namespace="${namespace}",pod=~"target-app.*"}[5m])`, label: 'Pod Restarts' }
  ],
  TargetAppMemoryLeak: [
