const enriched = $('PromQL Enrichment + Confidence').first().json;
const agentOutput = $input.first().json.output || '';

const { alertname, namespace, pod, severity, summary, description, signals, activeCount, totalCount, confidencePct, confidenceLabel, durationStr, status } = enriched;

// Signal bars (visual)
const bar = (val, max) => {
  const pct = max > 0 ? Math.min(val / max, 1) : (val > 0 ? 1 : 0);
  const filled = Math.round(pct * 8);
  return '█'.repeat(filled) + '░'.repeat(8 - filled);
};

const signalLines = signals.map(s => {
  const display = s.name === 'memory_bytes'
    ? `${Math.round(s.value / 1024 / 1024)}MB`
    : s.value.toFixed(1);
  const b = s.name === 'memory_bytes' ? bar(s.value, 500 * 1024 * 1024) : bar(s.value, 1);
  const icon = s.active ? '🔴' : '🟢';
  return `  ${icon} <b>${s.label.padEnd(16)}</b> ${b}  ${display}`;
}).join('\n');

// Extract SRE_ACTION if present
const actionMatch = agentOutput.match(/SRE_ACTION:\s*(.+)/);
const sreAction = actionMatch ? actionMatch[1].trim() : null;
const analysis = agentOutput.replace(/SRE_ACTION:.+/, '').trim();

// Confidence badge
const confBadge = { HIGH: '🔴 HIGH', MEDIUM: '🟡 MEDIUM', LOW: '🟢 LOW' }[confidenceLabel] || confidenceLabel;
const sevEmoji = severity === 'critical' ? '🚨' : '⚠️';
const statusLine = status === 'firing' ? '🔥 FIRING' : '✅ RESOLVED';

let msg = `${sevEmoji} <b>INCIDENT DETECTED</b>\n`;
msg += `━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📍 <b>${pod || 'target-app'}</b> / <code>${namespace}</code>\n`;
msg += `🏷 <b>${alertname}</b> — ${statusLine}\n`;
msg += `⏱ Duration: <b>${durationStr}</b>\n\n`;

msg += `📊 <b>Signal Correlation</b>\n`;
msg += `<code>${signalLines}</code>\n`;
msg += `Confidence: <b>${confBadge}</b> (${activeCount}/${totalCount} signals active)\n\n`;

msg += `🧠 <b>AI Assessment</b>\n`;
msg += `<i>${analysis}</i>\n\n`;

if (sreAction) {
  msg += `✅ <b>Recommended Action</b>\n`;
  msg += `<code>${sreAction}</code>\n\n`;
  msg += `💬 Reply <code>/approve &lt;totp&gt;</code> to execute via S4\n`;
} else {
  msg += `ℹ️ No write action required — monitoring only\n`;
}

msg += `━━━━━━━━━━━━━━━━━━━━\n`;
msg += `🕐 ${new Date().toISOString().replace('T', ' ').slice(0, 19)} UTC`;

return [{ json: { message: msg, sreAction, confidenceLabel, alertname, namespace } }];

const { alertname, namespace, confidenceLabel } = $input.first().json;
const msg = `❌ <b>S5 Error</b>\nFailed processing: ${alertname} (${namespace})\nConfidence was: ${confidenceLabel}`;
return [{ json: { message: msg } }];
